const today = new Date();
const days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

const schedule = [
  { day: 'Tuesday',   time: '10:00 AM', type: 'Main Educational Video',    duration: '12–18 min', emoji: '🎓' },
  { day: 'Wednesday', time: '10:00 AM', type: 'Quick Money Tip',            duration: '5–7 min',   emoji: '💡' },
  { day: 'Friday',    time: '10:00 AM', type: 'Comparison Video (A vs B)',  duration: '10–15 min', emoji: '⚖️' },
  { day: 'Sunday',    time: '10:00 AM', type: 'Myth-Busting / Story',       duration: '8–12 min',  emoji: '🔥' }
];

const week = `Week of ${today.toDateString()}`;

let scheduleText = '';
for (const s of schedule) {
  scheduleText += `\n${s.emoji} **${s.day} ${s.time}** – ${s.type} (${s.duration})`;
}

return [{ json: { week, scheduleText } }];
